INSERT INTO works (id, slug, title, author_id, dynasty, genre, collection, textbook_stage, difficulty_level, theme_label, tags_json, original_text, translation_text, background_text, appreciation_text, author_summary, source_name, source_collection, source_url, cover_asset_path) VALUES
('work-tao-hua-yuan-ji', 'tao-hua-yuan-ji', '桃花源记', 'author-陶渊明', '晋', '古文', '古文精选', '初中', 3, '理想桃源', '["理想社会", "田园", "想象"]', '晉太元中、太元、孝武帝年號。武陵人捕魚爲業。武陵、屬湖廣常德府、旁有桃源縣。緣溪行、忘路之遠近。便奇。忽逢桃花林。妙在以無意得之。夾岸數百步、中無雜樹、芳草鮮美、落英繽品平聲、紛。繽紛、雜亂貌。○寫出異境。漁人甚異之。復前行、欲窮其林。漁人亦不凡。林盡水源、便得一山。亦是無意中得。山有小口、髣髴若有光。善于點景。便捨船、從口入。初極狹、纔通人。俗人至此便反矣。復行數十步、豁然開朗。別有一天。土地平曠、屋舍儼然。有良田、美池、桑竹之屬。阡陌交通、雞犬相聞。其中往來種作、男女衣著、酌、悉如外人。敍山中人物。黃髮垂髫、調、並怡然自樂。黃髮、老人髮白轉黃也。髫、小兒垂髮。○純然古風。見漁人、乃大驚。問所從來、具答之。便要平聲、還家、設酒殺雞作食。村中聞有此人、咸來問訊。妙在漁人全無驚怪。自云先世避秦時亂、率妻子邑人、來此絕境、不復出焉、遂與外人間隔。到山來由。問今是何世、乃不知有漢、無論魏晉。真是目空古今。此人一一爲具言、所聞皆歎惋。歎惋者、悲外人屢遭世亂也。○敍兩邊問答簡括。餘人各復延至其家、皆出酒食。停數日、辭去。避世人多情如此。此中人語去聲、云、不足爲外人道也。叮嚀一句、逸韻悠然。旣出、得其船、便扶向路、處處誌之。漁人、亦大有心人。及郡下、詣太守說如此。詣、至也。太守卽遣人隨其往、尋向所誌、遂迷不復得路。太守欲問津而不得。南陽劉子驥、高尚士也、聞之、欣然規往、未果、尋病終。尋、俄也。○高士欲問津而不果。後遂無問津者。悠然而住。
